def fen_to_board(fen):
    rows = fen.split()[0].split('/')
    out = {}
    for r,row in enumerate(rows):
        rank = 8-r
        f = 0
        for ch in row:
            if ch.isdigit():
                f += int(ch)
            else:
                out[(rank, f)] = ch
                f += 1
    return out

fens = [
 "8/4k3/8/4K3/4P3/8/8/8",
 "4k3/8/8/4K3/8/8/8/8",
 "8/8/4k3/4P3/4K3/8/8/8",
 "3k4/8/3K4/3P4/8/8/8/8",
]
for f in fens:
    b = fen_to_board(f)
    print(f, "->", sorted([(8-r if False else r,c,p) for (r,c),p in b.items()]))
